import{_ as e,o as a,c as o,ae as i}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Multi-Touch Attribution","description":"","frontmatter":{"title":"Multi-Touch Attribution","slug":"multi-touch-attribution"},"headers":[],"relativePath":"marketer-hub/multi-touch-attribution.md","filePath":"marketer-hub/multi-touch-attribution.md"}'),r={name:"marketer-hub/multi-touch-attribution.md"};function n(l,t,s,h,u,d){return a(),o("div",null,[...t[0]||(t[0]=[i('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Our attribution process is based on the last-click model: the party responsible for the last click before the install is attributed with the install.</p><p>While the install itself (and consequently, the advertising partner or publisher who promoted the install) is the main metric of interest, it does not capture the entirety of what actually occurred to generate the install. Oftentimes, users are influenced by and interact with numerous partners (and their advertising efforts) before finally installing your mobile app.</p><p>Simply put, having insight into multi-touch attribution (MTA) offers you a more complete picture of the interactions and events that led up to an install (in contrast to simply measuring the winning impressions, clicks, and installs).</p><div class="warning custom-block"><p class="custom-block-title">Allowlist &amp; Self-Attribution Networks Only</p><p>At this time, Branch is providing insight into multi-touch attribution for Self-Attributing Networks (SANs) only. This includes the touch data for the following ad partners:</p><ul><li>Apple Ads</li><li>Facebook</li><li>Google Ads</li><li>Google Marketing Platform</li><li>Snap</li><li>Twitter</li></ul><p><strong>NOTE</strong>: Branch data privacy (e.g. GDPR) as well as SAN data restrictions still apply.</p><p>Please reach out to your Branch team to be added to the allowlist for this feature.</p></div><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><p>While Branch and other MMPs normally run on a Last Touch Attribution model, you can utilize this feature to get a better picture of the true customer journey by surfacing <em>all touchpoints</em> that led to a conversion.</p><h3 id="example-multi-touch-journey" tabindex="-1">Example Multi-Touch Journey <a class="header-anchor" href="#example-multi-touch-journey" aria-label="Permalink to &quot;Example Multi-Touch Journey&quot;">​</a></h3><p>For example, the user touches three different ad partners, Google, Snapchat, and Facebook (in that order) before converting. With MTA, you can see not only the awarded ad partner, but you can also see Google and Snapchat&#39;s touches along with the reason why they were not rewarded attribution for the conversion.</p><h2 id="view-san-multi-touch-data" tabindex="-1">View SAN Multi-Touch Data <a class="header-anchor" href="#view-san-multi-touch-data" aria-label="Permalink to &quot;View SAN Multi-Touch Data&quot;">​</a></h2><p>Branch currently supports two methods for extracting Multi-Touch Attribution data:</p><ol><li><a href="./custom-exports-api.html"><strong>Custom Exports (via UI and API)</strong></a></li><li><a href="./webhooks.html"><strong>Custom Webhooks (UI only)</strong></a></li></ol><h3 id="multi-touch-parameters" tabindex="-1">Multi-Touch Parameters <a class="header-anchor" href="#multi-touch-parameters" aria-label="Permalink to &quot;Multi-Touch Parameters&quot;">​</a></h3><p>When viewing all SAN touch data - not just attributed SAN touch data - you will receive all of the same fields as other Branch exports, but with the inclusion of the following three fields which specifically identify whether or not the touch was attributed to the SAN or a different ad partner.</p><table tabindex="0"><thead><tr><th>Field Name</th><th>Description</th><th>Options</th></tr></thead><tbody><tr><td><code>attributed</code></td><td>Whether or not the SAN was attributed. When TRUE, it is considered as a winning touch. When FALSE, is considered as a losing touch.</td><td>- TRUE - FALSE</td></tr><tr><td><code>attributed_false_reason_code</code></td><td>The <code>reason_code</code> field that defines why attribution was lost for this touch.</td><td>- NO_CLAIM - NO_LAST_TOUCH - OUT_OF_ATTRIBUTION_WINDOW - FRAUD_DETECTED - ERROR</td></tr><tr><td><code>attributed_false_winner</code></td><td>The attribution provider that was awarded. When PERSONA, there was a touch that was more recent (likely for a non-SAN)</td><td>- GOOGLE_AD_WORDS - FACEBOOK - SNAP - TWITTER - GOOGLE_MARKETING_PLATFORM - APPLE_SEARCH_AD - PERSONA</td></tr></tbody></table>',15)])])}const m=e(r,[["render",n]]);export{p as __pageData,m as default};
